  --collapsed-width: initial;
  --column-count: initial;
  --corner-height: initial;
  --corner-width: initial;
  --height: initial;
  --left: initial;
  --positioner-width: initial;
  --scroll-area-overflow-y-end: initial;
  --scroll-area-overflow-y-start: initial;
  --size: initial;
  --thickness: initial;
  --top: initial;
  --width: initial;

  /* Component state and animation */
  --depth: initial;
  --drawer-swipe-progress: initial;
  --drawer-swipe-strength: initial;
  --gap: initial;
  --marquee-delay: initial;
  --marquee-duration: initial;
  --marquee-loop-count: initial;
  --marquee-translate: initial;
  --nested-drawers: initial;
  --nested-layer-count: initial;
  --opacity: initial;
  --percent: initial;
  --scale: initial;
  --tour-layer: initial;
  --transition-duration: initial;
  --transition-property: initial;
  --transition-timing-function: initial;
  --x: initial;
  --y: initial;
}

